class Solution {
    public int minimumChanges(String s, int k) {
        int n = s.length();
        int[][] cost = new int[n][n];
        for (int l = 0; l < n; l++) {
            for (int r = l; r < n; r++) {
                cost[l][r] = minChanges(s, l, r);
            }
        }
        int[] dp = new int[n + 1];
        for (int i = 0; i <= n; i++) dp[i] = Integer.MAX_VALUE / 2;
        dp[0] = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < i; j++) {
                dp[i] = Math.min(dp[i], dp[j] + cost[j][i - 1]);
            }
        }
        int[] f = new int[k + 1];
        for (int i = 0; i <= k; i++) f[i] = Integer.MAX_VALUE / 2;
        f[0] = 0;
        for (int t = 1; t <= k; t++) {
            int[] g = new int[n + 1];
            for (int i = 0; i <= n; i++) g[i] = Integer.MAX_VALUE / 2;
            for (int i = 1; i <= n; i++) {
                for (int j = 0; j < i; j++) {
                    g[i] = Math.min(g[i], f[j] + cost[j][i - 1]);
                }
            }
            f = g;
        }
        return f[n];
    }

    private int minChanges(String s, int l, int r) {
        int len = r - l + 1;
        int min = Integer.MAX_VALUE;
        for (int d = 1; d < len; d++) {
            if (len % d != 0) continue;
            int changes = 0;
            for (int i = 0; i < d; i++) {
                int left = i;
                int right = len - d + i;
                while (left < right) {
                    if (s.charAt(l + left) != s.charAt(l + right)) changes++;
                    left += d;
                    right -= d;
                }
            }
            min = Math.min(min, changes);
        }
        return min;
    }
}
